155	        </MenuToggle>
156	      )}
157	    >
158	      <DropdownList>
159	        {pods.map((pod) => (
160	          <DropdownItem key={pod.metadata?.uid} value={pod}>
161	            <ResourceIcon kind="Pod" /> {pod.metadata?.name}
162	          </DropdownItem>
163	        ))}
164	      </DropdownList>
165	    </Dropdown>
