170	  <>
171	    {pods.map((pod) => (
172	      <Radio
173	        className="ols-plugin__radio"
174	        id={pod.metadata?.uid}
175	        isChecked={pod.metadata?.uid === selectedPod?.metadata?.uid}
176	        isLabelWrapped
177	        key={pod.metadata?.uid}
178	        label={
179	          <>
180	            <ResourceIcon kind="Pod" /> {pod.metadata?.name}
