212	type AttachLogModalProps = {
213	  isOpen: boolean;
214	  onClose: () => void;
215	  resource: K8sResourceKind;
216	};
217	
218	const AttachLogModal: React.FC<AttachLogModalProps> = ({ isOpen, onClose, resource }) => {
219	  const { t } = useTranslation('plugin__lightspeed-console-plugin');
220	
221	  const dispatch = useDispatch();
222	
223	  const isCronJob = resource.kind === 'CronJob';
224	  const isHPA = resource.kind === 'HorizontalPodAutoscaler';
225	  const kind = isHPA ? resource.spec?.scaleTargetRef?.kind : resource.kind;
226	  const name = isHPA ? resource.spec?.scaleTargetRef?.name : resource.metadata?.name;
227	  const namespace = resource.metadata?.namespace;
228	
229	  const showPodInput = kind !== 'Pod';
230	
231	  const [container, setContainer] = React.useState<string>(
232	    kind === 'Pod' ? resource.spec?.containers?.[0]?.name : undefined,
233	  );
234	  const [containers, setContainers] = React.useState<string[]>([]);
235	  const [error, setError] = React.useState<string>();
236	  const [isLoading, setIsLoading] = React.useState(false);
237	  const [lines, setLines] = React.useState<number>(DEFAULT_LOG_LINES);
238	  const [pod, setPod] = React.useState<K8sResourceKind>();
239	  const [preview, setPreview] = React.useState<string>();
240	  const [previewError, setPreviewError] = React.useState<string>();
241	  const [isPreviewLoading, setIsPreviewLoading] = React.useState(false);
242	
243	  const [scaleTarget, scaleTargetLoaded, scaleTargetError] = useK8sWatchResource<K8sResourceKind>(
244	    isHPA ? { isList: false, kind, name, namespace } : null,
245	  );
246	
247	  // For CronJobs, find jobs owned by the CronJob then select pods with a matching "job-name" label
248	  const [jobs, jobsLoaded, jobsError] = useK8sWatchResource<K8sResourceKind[]>(
249	    isCronJob ? { isList: true, kind: 'Job', namespace } : null,
250	  );
251	
252	  let selector;
253	  if (kind === 'Job') {
254	    selector = { 'job-name': name };
255	  } else if (isCronJob) {
256	    const ownedJobNames = (jobs || [])
257	      .filter((job) =>
258	        job.metadata?.ownerReferences?.find((owner) => owner.uid === resource?.metadata?.uid),
259	      )
260	      .map((job) => job.metadata?.name)
261	      .filter(Boolean);
262	    if (jobsLoaded && ownedJobNames.length > 0) {
263	      selector = { matchExpressions: [{ key: 'job-name', operator: 'In', values: ownedJobNames }] };
264	    } else if (jobsLoaded) {
265	      // No owned jobs found, so keep selector empty to yield zero pods
266	      selector = {
267	        matchExpressions: [
268	          { key: 'job-name', operator: 'Exists' },
269	          { key: 'job-name', operator: 'DoesNotExist' },
270	        ],
271	      };
272	    } else {
273	      selector = undefined;
274	    }
275	  } else if (kind === 'VirtualMachine' || kind === 'VirtualMachineInstance') {
276	    selector = { 'vm.kubevirt.io/name': name };
277	  } else if (scaleTarget && scaleTargetLoaded && !scaleTargetError) {
278	    selector = scaleTarget.spec?.selector;
279	  } else {
280	    selector = resource.spec?.selector;
281	  }
282	
283	  const [pods, podsLoaded, podsError] = useK8sWatchResource<K8sResourceKind[]>(
284	    showPodInput && selector !== undefined
285	      ? { isList: true, kind: 'Pod', namespace, selector }
286	      : null,
287	  );
288	
289	  const changePod = (newPod: K8sResourceKind) => {
290	    if (newPod) {
291	      setPod(newPod);
292	      const newContainers = newPod.spec?.containers?.map((c) => c.name).sort() ?? [];
293	      setContainers(newContainers);
294	      setContainer(newContainers[0]);
295	    }
296	  };
297	
298	  // Call onClose when the component is unmounted
299	  // eslint-disable-next-line react-hooks/exhaustive-deps
300	  React.useEffect(() => onClose, []);
301	
302	  // When the resource changes, reset the default pod (and container) options
303	  React.useEffect(() => {
304	    changePod(kind === 'Pod' ? resource : undefined);
305	  }, [kind, resource]);
306	
307	  // When the pods are loaded, use the first pod as the default pod value
308	  React.useEffect(() => {
309	    changePod(podsLoaded && pods ? pods[0] : undefined);
310	  }, [pods, podsLoaded]);
311	
312	  // eslint-disable-next-line react-hooks/exhaustive-deps
313	  const onLinesChange = React.useCallback(
314	    throttle((_e: SliderOnChangeEvent, value: number) => setLines(value), 50),
315	    [],
316	  );
317	
318	  // eslint-disable-next-line react-hooks/exhaustive-deps
319	  const loadPreview = React.useCallback(
320	    debounce((url: string) => {
321	      setIsPreviewLoading(true);
322	      setPreviewError(undefined);
323	      consoleFetchText(url)
324	        .then((response) => {
325	          if (isEmpty(response) || typeof response !== 'string') {
326	            setPreviewError(t('No logs found'));
327	          } else {
328	            setPreview(response);
329	          }
330	          setIsPreviewLoading(false);
331	        })
332	        .catch((err) => {
333	          setIsPreviewLoading(false);
334	          setPreviewError(err.message || t('Failed to fetch logs'));
335	        });
336	    }, 500),
337	    [],
338	  );
339	
340	  React.useEffect(() => {
341	    const podName = pod?.metadata?.name;
342	    if (container && lines && namespace && podName) {
343	      loadPreview(
344	        `/api/kubernetes/api/v1/namespaces/${namespace}/pods/${podName}/log?container=${container}&tailLines=${lines}`,
345	      );
346	    }
347	  }, [container, loadPreview, lines, namespace, pod]);
348	
349	  const onSubmit = React.useCallback(
350	    (e) => {
351	      e.preventDefault();
352	
353	      const podName = pod?.metadata?.name;
354	      const url = `/api/kubernetes/api/v1/namespaces/${namespace}/pods/${podName}/log?container=${container}&tailLines=${lines}`;
355	      setIsLoading(true);
356	      setError(undefined);
357	      consoleFetchText(url)
358	        .then((response: string) => {
359	          setIsLoading(false);
360	          if (isEmpty(response) || typeof response !== 'string') {
361	            setError(t('Failed to fetch logs'));
362	          } else {
363	            dispatch(
364	              attachmentSet(
365	                AttachmentTypes.Log,
366	                'Container',
367	                container,
368	                podName,
369	                namespace,
370	                `Most recent lines from the log for Container '${container}', belonging to pod '${podName}':\n\n${response?.trim()}`,
371	              ),
372	            );
373	            onClose();
374	          }
375	        })
376	        .catch((err) => {
377	          setIsLoading(false);
378	          setError(err.message || t('Failed to fetch logs'));
379	        });
380	    },
381	    [container, dispatch, lines, namespace, onClose, pod, t],
382	  );
383	
384	  return (
385	    <Modal isOpen={isOpen} onClose={onClose} title={t('Configure log attachment')}>
386	      <Text>
387	        {t(
388	          'You can select a container and specify the most recent number of lines of its log file to include as an attachment for detailed troubleshooting and analysis.',
389	        )}
390	      </Text>
391	      {scaleTargetError && (
392	        <Error title={t('Failed to load scale target')}>{scaleTargetError.message}</Error>
393	      )}
394	      <Form>
395	        {!scaleTargetError && (
396	          <>
397	            {showPodInput && (
398	              <FormGroup label="Pod">
399	                {podsError && <Error title={t('Failed to load pods')}>{podsError.message}</Error>}
400	                {jobsError && isCronJob && (
401	                  <Error title={t('Failed to load jobs')}>{jobsError.message}</Error>
402	                )}
403	                {podsLoaded && pods ? (
404	                  pods.length === 0 ? (
405	                    <Alert
406	                      className="ols-plugin__alert"
407	                      isInline
408	                      title={t('No pods found')}
409	                      variant="info"
410	                    >
411	                      {t('No pods found for {{kind}} {{name}}', { kind, name })}
412	                    </Alert>
413	                  ) : (
414	                    <PodInput pods={pods} selectedPod={pod} setPod={changePod} />
415	                  )
416	                ) : (
417	                  <Spinner isInline size="md" />
418	                )}
419	              </FormGroup>
420	            )}
421	            {(!showPodInput || (podsLoaded && pods && pods.length > 0)) && (
422	              <>
423	                <FormGroup label="Container">
424	                  <ContainerInput
425	                    containers={containers}
426	                    selectedContainer={container}
427	                    setContainer={setContainer}
428	                  />
429	                </FormGroup>
430	                <FormGroup label={t('Most recent {{lines}} lines', { lines })}>
431	                  <Slider max={100} min={1} onChange={onLinesChange} value={lines} />
432	                </FormGroup>
433	              </>
434	            )}
435	            {preview && (
436	              <CodeBlock
437	                actions={
438	                  <>
439	                    <CodeBlockAction />
440	                    <CodeBlockAction>
441	                      <CopyAction value={preview} />
442	                    </CodeBlockAction>
443	                  </>
444	                }
445	                className="ols-plugin__code-block ols-plugin__code-block--preview"
446	              >
447	                {isPreviewLoading && (
448	                  <CodeBlockCode className="ols-plugin__code-block-code">
449	                    <Spinner size="md" />
450	                  </CodeBlockCode>
451	                )}
452	                {!isPreviewLoading && !previewError && (
453	                  <CodeBlockCode
454	                    className="ols-plugin__code-block-code"
455	                    style={{ whiteSpace: 'pre' }}
456	                  >
457	                    {preview}
458	                  </CodeBlockCode>
459	                )}
460	              </CodeBlock>
461	            )}
462	            {previewError && <Error title={t('Failed to load logs')}>{previewError}</Error>}
463	          </>
464	        )}
465	        {error && <Error title={t('Failed to attach context')}>{error}</Error>}
466	        <ActionGroup>
467	          <Button
468	            isDisabled={!container || !!previewError}
469	            onClick={onSubmit}
470	            type="submit"
471	            variant="primary"
472	          >
473	            {t('Attach')}
474	          </Button>
475	          <Button onClick={onClose} type="submit" variant="link">
476	            {t('Cancel')}
477	          </Button>
478	        </ActionGroup>
479	        {isLoading && <Spinner size="md" />}
480	      </Form>
481	    </Modal>
482	  );
483	};
484	
485	export default AttachLogModal;

