213	type AttachLogModalProps = {
214	  isOpen: boolean;
215	  onClose: () => void;
216	  resource: K8sResourceKind;
217	};
218	
219	const AttachLogModal: React.FC<AttachLogModalProps> = ({ isOpen, onClose, resource }) => {
220	  const { t } = useTranslation('plugin__lightspeed-console-plugin');
221	
222	  const dispatch = useDispatch();
223	
224	  const isCronJob = resource.kind === 'CronJob';
225	  const isHPA = resource.kind === 'HorizontalPodAutoscaler';
226	  const kind = isHPA ? resource.spec?.scaleTargetRef?.kind : resource.kind;
227	  const name = isHPA ? resource.spec?.scaleTargetRef?.name : resource.metadata?.name;
228	  const namespace = resource.metadata?.namespace;
229	
230	  const showPodInput = kind !== 'Pod';
231	
232	  const [container, setContainer] = React.useState<string>(
233	    kind === 'Pod' ? resource.spec?.containers?.[0]?.name : undefined,
234	  );
235	  const [containers, setContainers] = React.useState<string[]>([]);
236	  const [error, setError] = React.useState<string>();
237	  const [isLoading, setIsLoading] = React.useState(false);
238	  const [lines, setLines] = React.useState<number>(DEFAULT_LOG_LINES);
239	  const [pod, setPod] = React.useState<K8sResourceKind>();
240	  const [preview, setPreview] = React.useState<string>();
241	  const [previewError, setPreviewError] = React.useState<string>();
242	  const [isPreviewLoading, setIsPreviewLoading] = React.useState(false);
243	
244	  const [scaleTarget, scaleTargetLoaded, scaleTargetError] = useK8sWatchResource<K8sResourceKind>(
245	    isHPA ? { isList: false, kind, name, namespace } : null,
246	  );
247	
248	  // For CronJobs, find jobs owned by the CronJob then select pods with a matching "job-name" label
249	  const [jobs, jobsLoaded, jobsError] = useK8sWatchResource<K8sResourceKind[]>(
250	    isCronJob ? { isList: true, kind: 'Job', namespace } : null,
251	  );
252	
253	  let selector;
254	  if (kind === 'Job') {
255	    selector = { 'job-name': name };
256	  } else if (isCronJob) {
257	    const ownedJobNames = (jobs || [])
258	      .filter((job) =>
259	        job.metadata?.ownerReferences?.find((owner) => owner.uid === resource?.metadata?.uid),
260	      )
261	      .map((job) => job.metadata?.name)
262	      .filter(Boolean);
263	    if (jobsLoaded && ownedJobNames.length > 0) {
264	      selector = { matchExpressions: [{ key: 'job-name', operator: 'In', values: ownedJobNames }] };
265	    } else if (jobsLoaded) {
266	      // No owned jobs found, so keep selector empty to yield zero pods
267	      selector = {
268	        matchExpressions: [
269	          { key: 'job-name', operator: 'Exists' },
270	          { key: 'job-name', operator: 'DoesNotExist' },
271	        ],
272	      };
273	    } else {
274	      selector = undefined;
275	    }
276	  } else if (kind === 'VirtualMachine' || kind === 'VirtualMachineInstance') {
277	    selector = { 'vm.kubevirt.io/name': name };
278	  } else if (scaleTarget && scaleTargetLoaded && !scaleTargetError) {
279	    selector = scaleTarget.spec?.selector;
280	  } else {
281	    selector = resource.spec?.selector;
282	  }
283	
284	  const [pods, podsLoaded, podsError] = useK8sWatchResource<K8sResourceKind[]>(
285	    showPodInput && selector !== undefined
286	      ? { isList: true, kind: 'Pod', namespace, selector }
287	      : null,
288	  );
289	
290	  const changePod = (newPod: K8sResourceKind) => {
291	    if (newPod) {
292	      setPod(newPod);
293	      const newContainers = newPod.spec?.containers?.map((c) => c.name).sort() ?? [];
294	      setContainers(newContainers);
295	      setContainer(newContainers[0]);
296	    }
297	  };
298	
299	  // Call onClose when the component is unmounted
300	  // eslint-disable-next-line react-hooks/exhaustive-deps
301	  React.useEffect(() => onClose, []);
302	
303	  // When the resource changes, reset the default pod (and container) options
304	  React.useEffect(() => {
305	    changePod(kind === 'Pod' ? resource : undefined);
306	  }, [kind, resource]);
307	
308	  // When the pods are loaded, use the first pod as the default pod value
309	  React.useEffect(() => {
310	    changePod(podsLoaded && pods ? pods[0] : undefined);
311	  }, [pods, podsLoaded]);
312	
313	  // eslint-disable-next-line react-hooks/exhaustive-deps
314	  const onLinesChange = React.useCallback(
315	    throttle((_e: SliderOnChangeEvent, value: number) => setLines(value), 50),
316	    [],
317	  );
318	
319	  // eslint-disable-next-line react-hooks/exhaustive-deps
320	  const loadPreview = React.useCallback(
321	    debounce((url: string) => {
322	      setIsPreviewLoading(true);
323	      setPreviewError(undefined);
324	      consoleFetchText(url)
325	        .then((response) => {
326	          if (isEmpty(response) || typeof response !== 'string') {
327	            setPreviewError(t('No logs found'));
328	          } else {
329	            setPreview(response);
330	          }
331	          setIsPreviewLoading(false);
332	        })
333	        .catch((err) => {
334	          setIsPreviewLoading(false);
335	          setPreviewError(err.message || t('Failed to fetch logs'));
336	        });
337	    }, 500),
338	    [],
339	  );
340	
341	  React.useEffect(() => {
342	    const podName = pod?.metadata?.name;
343	    if (container && lines && namespace && podName) {
344	      loadPreview(
345	        `/api/kubernetes/api/v1/namespaces/${namespace}/pods/${podName}/log?container=${container}&tailLines=${lines}`,
346	      );
347	    }
348	  }, [container, loadPreview, lines, namespace, pod]);
349	
350	  const onSubmit = React.useCallback(
351	    (e) => {
352	      e.preventDefault();
353	
354	      const podName = pod?.metadata?.name;
355	      const url = `/api/kubernetes/api/v1/namespaces/${namespace}/pods/${podName}/log?container=${container}&tailLines=${lines}`;
356	      setIsLoading(true);
357	      setError(undefined);
358	      consoleFetchText(url)
359	        .then((response: string) => {
360	          setIsLoading(false);
361	          if (isEmpty(response) || typeof response !== 'string') {
362	            setError(t('Failed to fetch logs'));
363	          } else {
364	            dispatch(
365	              attachmentSet(
366	                AttachmentTypes.Log,
367	                'Container',
368	                container,
369	                podName,
370	                namespace,
371	                `Most recent lines from the log for Container '${container}', belonging to pod '${podName}':\n\n${response?.trim()}`,
372	              ),
373	            );
374	            onClose();
375	          }
376	        })
377	        .catch((err) => {
378	          setIsLoading(false);
379	          setError(err.message || t('Failed to fetch logs'));
380	        });
381	    },
382	    [container, dispatch, lines, namespace, onClose, pod, t],
383	  );
384	
385	  return (
386	    <Modal isOpen={isOpen} onClose={onClose} title={t('Configure log attachment')}>
387	      <Content>
388	        {t(
389	          'You can select a container and specify the most recent number of lines of its log file to include as an attachment for detailed troubleshooting and analysis.',
390	        )}
391	      </Content>
392	      {scaleTargetError && (
393	        <Error title={t('Failed to load scale target')}>{scaleTargetError.message}</Error>
394	      )}
395	      <Form>
396	        {!scaleTargetError && (
397	          <>
398	            {showPodInput && (
399	              <FormGroup label="Pod">
400	                {podsError && <Error title={t('Failed to load pods')}>{podsError.message}</Error>}
401	                {jobsError && isCronJob && (
402	                  <Error title={t('Failed to load jobs')}>{jobsError.message}</Error>
403	                )}
404	                {podsLoaded && pods ? (
405	                  pods.length === 0 ? (
406	                    <Alert
407	                      className="ols-plugin__alert"
408	                      isInline
409	                      title={t('No pods found')}
410	                      variant="info"
411	                    >
412	                      {t('No pods found for {{kind}} {{name}}', { kind, name })}
413	                    </Alert>
414	                  ) : (
415	                    <PodInput pods={pods} selectedPod={pod} setPod={changePod} />
416	                  )
417	                ) : (
418	                  <Spinner isInline size="md" />
419	                )}
420	              </FormGroup>
421	            )}
422	            {(!showPodInput || (podsLoaded && pods && pods.length > 0)) && (
423	              <>
424	                <FormGroup label="Container">
425	                  <ContainerInput
426	                    containers={containers}
427	                    selectedContainer={container}
428	                    setContainer={setContainer}
429	                  />
430	                </FormGroup>
431	                <FormGroup label={t('Most recent {{lines}} lines', { lines })}>
432	                  <Slider max={100} min={1} onChange={onLinesChange} value={lines} />
433	                </FormGroup>
434	              </>
435	            )}
436	            {preview && (
437	              <CodeBlock
438	                actions={
439	                  <>
440	                    <CodeBlockAction />
441	                    <CodeBlockAction>
442	                      <CopyAction value={preview} />
443	                    </CodeBlockAction>
444	                  </>
445	                }
446	                className="ols-plugin__code-block ols-plugin__code-block--preview"
447	              >
448	                {isPreviewLoading && (
449	                  <CodeBlockCode className="ols-plugin__code-block-code">
450	                    <Spinner size="md" />
451	                  </CodeBlockCode>
452	                )}
453	                {!isPreviewLoading && !previewError && (
454	                  <CodeBlockCode
455	                    className="ols-plugin__code-block-code"
456	                    style={{ whiteSpace: 'pre' }}
457	                  >
458	                    {preview}
459	                  </CodeBlockCode>
460	                )}
461	              </CodeBlock>
462	            )}
463	            {previewError && <Error title={t('Failed to load logs')}>{previewError}</Error>}
464	          </>
465	        )}
466	        {error && <Error title={t('Failed to attach context')}>{error}</Error>}
467	        <ActionGroup>
468	          <Button
469	            isDisabled={!container || !!previewError}
470	            onClick={onSubmit}
471	            type="submit"
472	            variant="primary"
473	          >
474	            {t('Attach')}
475	          </Button>
476	          <Button onClick={onClose} type="submit" variant="link">
477	            {t('Cancel')}
478	          </Button>
479	        </ActionGroup>
480	        {isLoading && <Spinner size="md" />}
481	      </Form>
482	    </Modal>
483	  );
484	};
485	
486	export default AttachLogModal;

